const path = require('path');
const fs = require('fs');

const input = $json || {};

const rawPath = String(input.primary_pdf_path || '').trim();
const cleanPath = rawPath
  .replace(/[\r\n]+/g, '')
  .replace(/\u00A0/g, ' ')
  .replace(/[\u200e\u200f\u202a-\u202e\u2066-\u2069]/g, '')
  .trim();

if (!cleanPath) throw new Error('Missing primary_pdf_path');

const fileName = path.basename(cleanPath);
let baseName = path.basename(cleanPath, path.extname(cleanPath));
baseName = baseName.replace(/\s+/g, ' ').trim();

const toAsciiDigits = (s) => s.replace(/[٠-٩]/g, d => String('٠١٢٣٤٥٦٧٨٩'.indexOf(d)));
const ascii = toAsciiDigits(baseName);
const numMatch = ascii.match(/(\d{1,2})/);
const parsedNum = numMatch ? parseInt(numMatch[1], 10) : null;

const parts = cleanPath.split(path.sep);
const downloadsIdx = parts.lastIndexOf('downloads');
const relParts = downloadsIdx >= 0 ? parts.slice(downloadsIdx + 1, -1) : [];
const topFolder = (relParts[0] || '').toLowerCase();
const subFolder = (relParts[1] || '').toLowerCase();

const COURSE_MAP = {
  botany: 'B101',
  chemistry: 'C102',
  chemistry_practical: 'C104',
  computer_science: 'COMP101',
  geology: 'G102',
  math: 'M102',
  physics: 'P102',
  physics_practical: 'P104',
  zoology: 'Z102'
};

const courseCode = input.course_code || COURSE_MAP[topFolder] || '';

let instructor = input.instructor || null;
let section = input.section || null;

if (courseCode === 'P102') {
  if (!instructor) {
    if (subFolder.includes('essam')) instructor = 'Dr. Essam';
    if (subFolder.includes('mohammed')) instructor = 'Dr. Mohammed';
    if (subFolder.includes('wagida')) instructor = 'Dr. Wagida';
  }
}

if (courseCode === 'C102') {
  if (!section) {
    if (subFolder.includes('physical')) section = 'Physical Chemistry';
    if (subFolder.includes('organic')) section = 'Organic Chemistry';
  }
}

let lectureTitle = '';
if (courseCode === 'P104') {
  lectureTitle = baseName;
} else if (courseCode === 'C104') {
  lectureTitle = parsedNum ? `Section ${parsedNum}` : baseName;
} else {
  lectureTitle = parsedNum ? `Lecture ${parsedNum}` : baseName;
}

const lectureNumber = parsedNum ?? (input.lecture_number != null ? parseInt(input.lecture_number, 10) : null);

// ===== Drive Folder Mapping (REPLACE IDs) =====
const DRIVE_FOLDERS = {
  root: 'REPLACE_WITH_ROOT_FOLDER_ID',
  botany: 'REPLACE_WITH_BOTANY_FOLDER_ID',
  chemistry: {
    physical: 'REPLACE_WITH_C102_PHYSICAL_FOLDER_ID',
    organic: 'REPLACE_WITH_C102_ORGANIC_FOLDER_ID'
  },
  chemistry_practical: 'REPLACE_WITH_C104_FOLDER_ID',
  computer_science: 'REPLACE_WITH_COMP101_FOLDER_ID',
  geology: 'REPLACE_WITH_G102_FOLDER_ID',
  math: 'REPLACE_WITH_M102_FOLDER_ID',
  physics: {
    'dr-essam': 'REPLACE_WITH_P102_ESSAM_FOLDER_ID',
    'dr-mohammed': 'REPLACE_WITH_P102_MOHAMMED_FOLDER_ID',
    'dr-wagida': 'REPLACE_WITH_P102_WAGIDA_FOLDER_ID'
  },
  physics_practical: 'REPLACE_WITH_P104_FOLDER_ID',
  zoology: 'REPLACE_WITH_Z102_FOLDER_ID'
};

let driveParentId = DRIVE_FOLDERS.root;
if (topFolder === 'physics' && DRIVE_FOLDERS.physics) {
  driveParentId = DRIVE_FOLDERS.physics[subFolder] || DRIVE_FOLDERS.root;
} else if (topFolder === 'chemistry' && DRIVE_FOLDERS.chemistry) {
  driveParentId = DRIVE_FOLDERS.chemistry[subFolder] || DRIVE_FOLDERS.root;
} else if (DRIVE_FOLDERS[topFolder]) {
  driveParentId = DRIVE_FOLDERS[topFolder];
}

const fileExists = fs.existsSync(cleanPath);

return [{
  json: {
    ...input,
    primary_pdf_path: cleanPath,
    file_base: baseName,
    drive_file_name: fileName,
    drive_parent_id: driveParentId,
    course_code: courseCode,
    lecture_title: lectureTitle,
    lecture_number: lectureNumber,
    instructor,
    section,
    folder_top: topFolder,
    folder_sub: subFolder,
    file_exists: fileExists
  }
}];

const parts = Array.isArray($json.youtubeParts) ? $json.youtubeParts : [];
const videoParts = parts
  .map((p, idx) => {
    if (!p) return null;
    const url = p.url || p.link || p.youtubeUrl || p.youtube_url;
    if (!url) return null;
    return { title: (p.title || p.name || `Part ${idx + 1}`).toString().trim(), url };
  })
  .filter(Boolean);

const youtubeUrl = videoParts.length ? videoParts[0].url : null;

return [{ json: { ...$json, videoParts, youtubeUrl } }];
